<?php
require_once __DIR__ . '/../helpers/rooms.php';$me=current_user();$d=input();$id=(int)($d['room_id']??0);$room=room_by_id($id);if(!$room||$room['status']!=='active')json_response(['success'=>false,'message'=>'Room is closed'],404);
if(blocked_between((int)$me['id'],(int)$room['owner_id']))json_response(['success'=>false,'message'=>'You cannot join this room'],403);
$kick=db()->prepare('SELECT id FROM room_kicks WHERE room_id=? AND user_id=?');$kick->execute([$id,$me['id']]);if($kick->fetch())json_response(['success'=>false,'message'=>'You were removed from this room'],403);
if((int)$room['owner_id']!==(int)$me['id']&&(int)$room['is_locked']===1&&!password_verify((string)($d['password']??''),(string)$room['password_hash']))json_response(['success'=>false,'message'=>'Invalid Room Password'],403);
$role=(int)$room['owner_id']===(int)$me['id']?'owner':'listener';db()->prepare("INSERT INTO room_participants(room_id,user_id,role,left_at,last_seen_at) VALUES(?,?,?,NULL,NOW()) ON DUPLICATE KEY UPDATE role=IF(role IN('owner','coadmin','speaker'),role,VALUES(role)),left_at=NULL,last_seen_at=NOW()")->execute([$id,$me['id'],$role]);db()->prepare('INSERT INTO room_history(room_id,user_id) VALUES(?,?)')->execute([$id,$me['id']]);refresh_room_count($id);room_system_message($id,($me['name']?:$me['username']).' joined the room');json_response(['success'=>true,'role'=>room_role($id,(int)$me['id'])]);
